const difficultyLabel: Record<string, string> = {
  easy: 'Easy',
  medium: 'Some effort',
  hard: 'Ambitious',
}

function formatTime(minutes: number): string {
  if (minutes < 60) return `${minutes} mins`
  const h = Math.floor(minutes / 60)
  const m = minutes % 60
  return m > 0 ? `${h} hr ${m} mins` : `${h} hr`
}

export default function HomePage() {
  return (
    <Suspense>
      <HomePageInner />
    </Suspense>
  )
}

const INGREDIENT_PHOTOS: Record<string, string> = {
  chicken: '/icons/chicken.jpg',
  pork: '/icons/pork.jpg',
  beef: '/icons/beef.jpg',
  fish: '/icons/fish.jpg',
  potato: '/icons/potato.jpg',
  pasta: '/icons/pasta.jpg',
  rice: '/icons/rice.jpg',
  noodles: '/icons/noodle.jpg',
}

function IngredientCard({ ingredient, isSelected, onToggle }: {
  ingredient: string
  isSelected: boolean
  onToggle: () => void
}) {
  const [bursting, setBursting] = useState(false)
  const [hovered, setHovered] = useState(false)
  const photo = INGREDIENT_PHOTOS[ingredient]

  function handleClick() {
    if (!isSelected) setBursting(true)
    onToggle()
  }

  return (
    <div
      className={`relative transition-transform duration-200 ease-out ${isSelected ? 'scale-95' : hovered ? 'scale-110' : 'scale-100'}`}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
    <div className={`relative ${!isSelected && hovered ? 'animate-levitate' : ''}`}>
      {bursting && (
        <span
          className="impact-burst"
          onAnimationEnd={() => setBursting(false)}
        />
      )}
      <button
        onClick={handleClick}
        className="relative flex flex-col items-center justify-center gap-2 aspect-[2/3] w-full rounded-3xl border border-black font-ui font-bold text-xl capitalize tracking-tight overflow-hidden"
        style={!photo ? { backgroundColor: isSelected ? '#f4f4f5' : '#ffffff' } : undefined}
      >
        {photo ? (
          <>
            <div
              className="absolute inset-0"
              style={{ backgroundImage: `url(${photo})`, backgroundSize: 'cover', backgroundPosition: 'center' }}
            />
            {isSelected && <div className="absolute inset-0 bg-zinc-50/70" />}
            <span className="absolute bottom-3 left-3 right-3 bg-zinc-50 border border-black rounded-2xl py-2 text-zinc-950 text-center z-10">{ingredient}</span>
          </>
        ) : (
          <span className="text-zinc-950">{ingredient}</span>
        )}
      </button>
    </div>
    </div>
  )
}

function HomePageInner() {
  const searchParams = useSearchParams()

  const [selected, setSelected] = useState<Set<string>>(() => {
    const param = searchParams.get('ingredients')
    return param ? new Set(param.split(',').filter(Boolean)) : new Set()
  })

  function toggle(ingredient: string) {
    setSelected(prev => {
      const next = new Set(prev)
      if (next.has(ingredient)) {
        next.delete(ingredient)
      } else {
        next.add(ingredient)
      }
      return next
    })
  }

  useEffect(() => {
    const url = selected.size > 0
      ? `/?ingredients=${encodeURIComponent([...selected].join(','))}`
      : '/'
    window.history.replaceState(null, '', url)
  }, [selected])


  const recipesSectionRef = useRef<HTMLDivElement>(null)
  const [recipesInView, setRecipesInView] = useState(false)

  useEffect(() => {
    const el = recipesSectionRef.current
    if (!el) return
    const observer = new IntersectionObserver(
      ([entry]) => setRecipesInView(entry.isIntersecting),
      { threshold: 0.1 }
    )
    observer.observe(el)
    return () => observer.disconnect()
  }, [])

  const displayedRecipes = useMemo(() => {
    if (selected.size === 0) return recipes
    const selectedList = [...selected].map(s => s.toLowerCase())
    return recipes.filter(recipe =>
      recipe.ingredients.some(ingredient =>
        selectedList.some(sel =>
          ingredient.name.toLowerCase().includes(sel) || sel.includes(ingredient.name.toLowerCase())
        )
      )
    )
  }, [selected])

  const filterKey = [...selected].sort().join(',')

  return (
    <>
      <nav className="sticky top-0 z-50 bg-zinc-50 border-b border-black flex items-center justify-center px-6 py-4">
        <span className="font-display font-bold text-xl text-zinc-950 tracking-tight">Pantrio</span>
      </nav>
      <main>
        {/* Hero filter section */}
        <div className="bg-teal py-16 border-b border-black">
          <div className="w-full max-w-3xl mx-auto px-4 flex flex-col items-center text-center">
          <h1 className="font-display hero-heading text-7xl sm:text-8xl lg:text-9xl mb-12 text-zinc-950 tracking-tight">
            What are you{' '}
            <span className="whitespace-nowrap">
              <span className="relative inline-block">
                <span className="text-hatch-shadow absolute top-[5px] left-[5px] pointer-events-none select-none" aria-hidden="true">working</span>
                <span className="text-outlined relative">working</span>
              </span>
              {' '}with?
            </span>
          </h1>

          <div className="w-full flex flex-col gap-4">
            <div className="grid grid-cols-4 gap-3">
              {PROTEINS.map(ingredient => <IngredientCard key={ingredient} ingredient={ingredient} isSelected={selected.has(ingredient)} onToggle={() => toggle(ingredient)} />)}
            </div>
            <div className="grid grid-cols-4 gap-3">
              {STARCHES.map(ingredient => <IngredientCard key={ingredient} ingredient={ingredient} isSelected={selected.has(ingredient)} onToggle={() => toggle(ingredient)} />)}
            </div>
          </div>
          </div>
        </div>

        {/* Recipe grid */}
        <div ref={recipesSectionRef} className="py-12">
          <div className="w-full max-w-3xl mx-auto px-4">
          <p className="font-display text-zinc-950 tracking-tight mb-6 text-center">
            {selected.size === 0
              ? `All ${recipes.length}. Take your pick.`
              : displayedRecipes.length === 0
              ? null
              : `${displayedRecipes.length} recipe${displayedRecipes.length === 1 ? '' : 's'}. Start somewhere.`}
          </p>

          <div key={filterKey} className="animate-fade-up">
            {displayedRecipes.length === 0 ? (
              <div className="text-center py-20">
                <p className="font-display text-3xl text-zinc-950 tracking-tight mb-3">
                  Nothing matched.
                </p>
                <p className="font-sans text-sm text-zinc-950">
                  Either your fridge is very sparse or very unusual.
                </p>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                {displayedRecipes.map(recipe => {
                  const href = selected.size > 0
                    ? `/recipe/${recipe.id}?ingredients=${encodeURIComponent([...selected].join(','))}`
                    : `/recipe/${recipe.id}`

                  return (
                    <div key={recipe.id} className="hatch-shadow h-full">
                      <Link
                        href={href}
                        className="group flex flex-col h-full bg-white border border-black rounded-3xl hover:translate-x-[4px] hover:translate-y-[4px] transition-transform duration-150 ease-out overflow-hidden"
                      >
                        <div className="p-5">
                          <h2 className="font-display text-2xl leading-tight text-zinc-950 tracking-tight mb-2 group-hover:opacity-70 transition-none">
                            {recipe.name}
                          </h2>
                          <p className="font-sans text-xs leading-snug text-zinc-950 mb-4 line-clamp-2">
                            {recipe.summary}
                          </p>
                          <div className="flex items-center gap-3 font-sans text-xs text-zinc-950 font-bold uppercase tracking-wide">
                            <span>{formatTime(recipe.time)}</span>
                            <span>·</span>
                            <span>{difficultyLabel[recipe.difficulty]}</span>
                          </div>
                        </div>
                      </Link>
                    </div>
                  )
                })}
              </div>
            )}
          </div>
          </div>
        </div>

        {/* Sticky recipe count bar */}
        <div className={`fixed bottom-0 left-0 right-0 flex justify-center pb-6 pointer-events-none transition-all duration-300 ease-out ${selected.size > 0 && !recipesInView ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0'}`}>
          <div className="border border-black rounded-2xl px-6 py-3 font-ui font-bold text-lg pointer-events-auto bg-zinc-950 text-yellow-300 whitespace-nowrap">
            {displayedRecipes.length} recipe{displayedRecipes.length === 1 ? '' : 's'} found.
          </div>
        </div>
      </main>
    </>
  )
}
